'use strict';
/**
 * Digitized from the existing, fully-authored assessment instructor guides
 * (lair-app/lair-content/Linux_Curriculum_Pre|PostAssessment_Instructor_ANSWERKEY.docx,
 * also mirrored in the "lair" R2 bucket at the bucket root). Both are already-written
 * 50-question multiple-choice exams with per-question rationale — this seeder converts
 * them into the app's quiz question schema verbatim, it does not invent new questions.
 *
 * 1 point per question (max_score 50) so a student's raw score maps directly onto the
 * instructor guide's own readiness bands (45-50 / 35-44 / 20-34 / <20), which are stated
 * in terms of "questions correct out of 50", not weighted points.
 *
 * Pre-assessment: diagnostic only, administered before Day 1 (order_index 50, before
 * Day 1's 100). Post-assessment: retention/mastery check after Day 3 (order_index 400,
 * after Day 3's 330). Neither is a pass/fail gate — matches the source document's own
 * "Instructor Notes" section.
 *
 * Run: node-only via sequelize-cli db:seed (see 20240102000001/2 for the pattern).
 */
